import{_ as e,o as i,c as s,a2 as t}from"./chunks/framework.DCVnL8g5.js";const u=JSON.parse('{"title":"Topics, partitions y brokers","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/kafka/02-topics-partitions-y-brokers.md","filePath":"data-engineering/kafka/02-topics-partitions-y-brokers.md","lastUpdated":1782521464000}'),n={name:"data-engineering/kafka/02-topics-partitions-y-brokers.md"};function o(r,a,p,l,d,c){return i(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="topics-partitions-y-brokers" tabindex="-1">Topics, partitions y brokers <a class="header-anchor" href="#topics-partitions-y-brokers" aria-label="Permalink to &quot;Topics, partitions y brokers&quot;">​</a></h1><p>Kafka organiza los eventos en topics. Cada topic se divide en partitions y esas partitions viven repartidas entre brokers.</p><h2 id="topic" tabindex="-1">Topic <a class="header-anchor" href="#topic" aria-label="Permalink to &quot;Topic&quot;">​</a></h2><p>Un topic es una categoria logica de eventos.</p><p>Ejemplos:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>orders.created</span></span>
<span class="line"><span>orders.cancelled</span></span>
<span class="line"><span>payments.authorized</span></span>
<span class="line"><span>users.registered</span></span></code></pre></div><p>Un topic debe representar un flujo de eventos con significado de negocio o tecnico claro.</p><h2 id="partition" tabindex="-1">Partition <a class="header-anchor" href="#partition" aria-label="Permalink to &quot;Partition&quot;">​</a></h2><p>Una partition es un log ordenado e inmutable.</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  T[&quot;Topic orders.created&quot;] --&gt; P0[&quot;Partition 0&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  T --&gt; P1[&quot;Partition 1&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  T --&gt; P2[&quot;Partition 2&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  P0 --&gt; E0[&quot;offset 0,1,2...&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  P1 --&gt; E1[&quot;offset 0,1,2...&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  P2 --&gt; E2[&quot;offset 0,1,2...&quot;]</span></span></code></pre></div><p>Kafka garantiza orden dentro de una partition, no entre partitions distintas.</p><h2 id="offset" tabindex="-1">Offset <a class="header-anchor" href="#offset" aria-label="Permalink to &quot;Offset&quot;">​</a></h2><p>El offset es la posicion de un evento dentro de una partition.</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>topic: orders.created</span></span>
<span class="line"><span>partition: 2</span></span>
<span class="line"><span>offset: 1538</span></span></code></pre></div><p>El offset no es global. Solo tiene sentido dentro de topic + partition.</p><h2 id="broker" tabindex="-1">Broker <a class="header-anchor" href="#broker" aria-label="Permalink to &quot;Broker&quot;">​</a></h2><p>Un broker es un servidor Kafka. Un cluster tiene varios brokers para repartir carga y replicas.</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  B1[&quot;Broker 1&quot;] --&gt; P0[&quot;orders-0 leader&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  B2[&quot;Broker 2&quot;] --&gt; P1[&quot;orders-1 leader&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  B3[&quot;Broker 3&quot;] --&gt; P2[&quot;orders-2 leader&quot;]</span></span></code></pre></div><h2 id="leader-y-replicas" tabindex="-1">Leader y replicas <a class="header-anchor" href="#leader-y-replicas" aria-label="Permalink to &quot;Leader y replicas&quot;">​</a></h2><p>Cada partition tiene un leader. Productores y consumidores hablan con el leader. Las replicas copian los datos.</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TB</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  L[&quot;Broker 1\\npartition leader&quot;] --&gt; R1[&quot;Broker 2\\nreplica&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  L --&gt; R2[&quot;Broker 3\\nreplica&quot;]</span></span></code></pre></div><p>Si el leader falla, Kafka puede elegir una replica sincronizada como nuevo leader.</p><h2 id="replication-factor" tabindex="-1">Replication factor <a class="header-anchor" href="#replication-factor" aria-label="Permalink to &quot;Replication factor&quot;">​</a></h2><p><code>replication.factor=3</code> significa que cada partition tiene tres copias.</p><p>Ventajas:</p><ul><li>Tolerancia a fallos.</li><li>Mantenimiento sin perder disponibilidad.</li><li>Menor riesgo de perdida de datos.</li></ul><p>Costes:</p><ul><li>Mas disco.</li><li>Mas red.</li><li>Mas coordinacion.</li></ul><h2 id="partitions-y-paralelismo" tabindex="-1">Partitions y paralelismo <a class="header-anchor" href="#partitions-y-paralelismo" aria-label="Permalink to &quot;Partitions y paralelismo&quot;">​</a></h2><p>El numero de partitions limita el paralelismo de consumo dentro de un consumer group.</p><p>Si un topic tiene 6 partitions, un consumer group puede tener hasta 6 consumidores trabajando en paralelo de forma efectiva.</p><h2 id="elegir-numero-de-partitions" tabindex="-1">Elegir numero de partitions <a class="header-anchor" href="#elegir-numero-de-partitions" aria-label="Permalink to &quot;Elegir numero de partitions&quot;">​</a></h2><p>Considera:</p><ul><li>Throughput esperado.</li><li>Numero de consumidores paralelos.</li><li>Retencion y tamano de eventos.</li><li>Necesidad de orden por clave.</li><li>Coste operativo.</li></ul><p>No crees cientos de partitions sin motivo. Las partitions tambien tienen coste.</p><h2 id="clave-de-particion" tabindex="-1">Clave de particion <a class="header-anchor" href="#clave-de-particion" aria-label="Permalink to &quot;Clave de particion&quot;">​</a></h2><p>El producer puede enviar una key. Kafka usa esa key para decidir partition.</p><p>Ejemplo:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>key = order_id</span></span></code></pre></div><p>Todos los eventos del mismo pedido iran a la misma partition, manteniendo orden para ese pedido.</p><h2 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h2><ul><li>Usa nombres de topics claros y estables.</li><li>Define keys pensando en orden y distribucion.</li><li>Usa replication factor 3 en produccion cuando sea posible.</li><li>Evita topics con partitions insuficientes para crecer.</li><li>No dependas de orden global.</li></ul>`,42)])])}const k=e(n,[["render",o]]);export{u as __pageData,k as default};
